/**
 * CalendarScheduler - Main Calendar Component
 *
 * This is the top-level component that orchestrates the entire calendar scheduling experience.
 * It manages:
 * - View state (month/week/day/agenda)
 * - Date navigation (previous/next based on current view)
 * - Timezone selection (viewer can change their timezone)
 * - Rendering the appropriate sub-view component
 *
 * @example
 * <CalendarScheduler
 *   availability={[
 *     { day: 'monday', startTime: '09:00', endTime: '17:00', enabled: true },
 *     { day: 'wednesday', startTime: '10:00', endTime: '15:00', enabled: true },
 *   ]}
 *   bookedSlots={[{ date: '2024-03-15', time: '10:00' }]}
 *   slotDuration={30}
 *   adminTimeZone="America/New_York"
 *   onDateSelect={(date) => setSelectedDate(date)}
 *   onSlotSelect={(date, time) => handleBooking(date, time)}
 * />
 */

"use client";

import {
  addDays,
  addMonths,
  addWeeks,
  endOfWeek,
  format,
  isBefore,
  startOfMonth,
  startOfWeek,
  subDays,
  subMonths,
  subWeeks,
} from "date-fns";
import { ChevronLeft, ChevronRight, Globe } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { AgendaView } from "./agenda-view";
import { DayView } from "./day-view";
import { detectBrowserTimezone } from "./helpers";
import { MonthView } from "./month-view";
import { TimezoneSelect } from "./timezone-selector";
import { ALL_TIMEZONES } from "./timezones";
import type { CalendarSchedulerProps, ViewType } from "./types";
import { ViewSwitcher } from "./view-switcher";
import { WeekView } from "./week-view";

/**
 * Internal component that handles the calendar navigation logic.
 * Manages view state, current date, and timezone preferences.
 */
export function CalendarScheduler({
  availability,
  bookedSlots = [],
  selectedDate,
  onDateSelect,
  onSlotSelect,
  adminTimeZone = "UTC",
  defaultViewerTimeZone,
  slotDuration,
}: CalendarSchedulerProps) {
  // Current view mode (defaults to month view)
  const [view, setView] = useState<ViewType>("month");
  // The date currently being displayed (for navigation)
  const [current, setCurrent] = useState<Date>(selectedDate ?? new Date());
  // Viewer's timezone state (dual state for sync purposes)
  const [vTz, setVtZ] = useState(
    defaultViewerTimeZone ?? detectBrowserTimezone(),
  );
  const [viewerTZ, setViewerTZ] = useState<string>(vTz);
  /** Handler for timezone changes - updates both state variables */
  function handleZoneChange(tz: string) {
    setViewerTZ(tz);
    setVtZ(tz);
  }

  /**
   * Navigates forward or backward based on current view.
   * Month/Agenda: moves by 1 month
   * Week: moves by 1 week
   * Day: moves by 1 day
   */
  function navigate(dir: 1 | -1) {
    if (view === "month")
      setCurrent((c) => (dir === 1 ? addMonths(c, 1) : subMonths(c, 1)));
    if (view === "week")
      setCurrent((c) => (dir === 1 ? addWeeks(c, 1) : subWeeks(c, 1)));
    if (view === "day")
      setCurrent((c) => (dir === 1 ? addDays(c, 1) : subDays(c, 1)));
    if (view === "agenda")
      setCurrent((c) => (dir === 1 ? addMonths(c, 1) : subMonths(c, 1)));
  }

  /** Generates the title text for the header based on current view and date */
  function getTitle() {
    if (view === "month") return format(current, "MMMM yyyy");
    if (view === "week") {
      const ws = startOfWeek(current, { weekStartsOn: 0 });
      const we = endOfWeek(current, { weekStartsOn: 0 });
      return `${format(ws, "MMM d")} – ${format(we, "MMM d, yyyy")}`;
    }
    if (view === "day") return format(current, "EEEE, MMMM d, yyyy");
    return `Agenda – ${format(current, "MMMM yyyy")}`;
  }

  // Resolve human-readable timezone labels for the footer
  const adminLabel =
    ALL_TIMEZONES.find((z) => z.value === adminTimeZone)?.label ??
    adminTimeZone;
  const viewerLabel =
    ALL_TIMEZONES.find((z) => z.value === viewerTZ)?.label ?? viewerTZ;

  /** Common props passed to all view components */
  const sharedProps = {
    current,
    availability,
    bookedSlots,
    slotDuration,
    adminTZ: adminTimeZone,
    viewerTZ: vTz,
    onDateSelect: (d: Date) => {
      setCurrent(d);
      onDateSelect(d);
    },
    onSlotSelect,
  };

  return (
    <div className="flex flex-col rounded-2xl border overflow-scroll no-scrollbar bg-background w-full">
      <div className="flex items-center justify-between gap-3 px-4 overflow-scroll no-scrollbar py-3 border-b bg-muted/30 flex-wrap gap-y-2">
        <div className="flex items-center gap-2">
          <Button
            variant="secondary"
            size="icon"
            className="h-7 w-7"
            onClick={() => navigate(-1)}
            disabled={
              view === "month" &&
              isBefore(
                startOfMonth(subMonths(current, 1)),
                startOfMonth(new Date()),
              )
            }
          >
            <ChevronLeft className="h-4 w-4" />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="h-7 text-xs font-semibold px-2"
          >
            {getTitle()}
          </Button>
          <Button
            variant="secondary"
            size="icon"
            className="h-7 w-7"
            onClick={() => navigate(1)}
          >
            <ChevronRight className="h-4 w-4" />
          </Button>
          {/*<Button
            onClick={() => setCurrent(new Date())}
            variant="ghost"
            size="sm"
            className="h-7 text-xs font-semibold px-2"
          >
            Today
          </Button>*/}
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <TimezoneSelect
            value={vTz}
            onChange={handleZoneChange}
            label="Your timezone"
          />
          <ViewSwitcher view={view} onChange={setView} />
        </div>
      </div>

      {/*<div className="sm:hidden px-4 pt-2 pb-0">
        <p className="text-sm font-semibold text-foreground">{getTitle()}</p>
      </div>*/}

      {/*{adminTimeZone !== viewerTZ && (
        <div className="flex items-center gap-2 px-4 py-2 bg-blue-50/70 dark:bg-blue-950/20 border-b text-xs text-blue-700 dark:text-blue-300">
          <Globe className="h-3.5 w-3.5 shrink-0" />
          <span>
            Times shown in <strong>{viewerLabel}</strong>. Host is in{" "}
            <strong>{adminLabel}</strong>. Hover any slot to see both times.
          </span>
        </div>
      )}*/}

      <div className="flex-1">
        {view === "month" && (
          <MonthView {...sharedProps} selectedDate={current} />
        )}
        {view === "week" && (
          <WeekView {...sharedProps} selectedDate={selectedDate} />
        )}
        {view === "day" && <DayView {...sharedProps} />}
        {view === "agenda" && <AgendaView {...sharedProps} />}
      </div>

      <div className="flex items-center gap-4 px-4 py-2 border-t bg-muted/20 w-full text-[10px] text-muted-foreground flex-wrap">
        {/*<span className="flex items-center gap-1.5">
					<span className="h-2 w-2 rounded-sm bg-emerald-400/70" /> Available
				</span>
				<span className="flex items-center gap-1.5">
					<span className="h-2 w-2 rounded-sm bg-rose-400/70" /> Booked
				</span>
				<span className="flex items-center gap-1.5">
					<span className="h-2 w-2 bg-primary/70 rounded-full" /> Today
				</span>*/}
        <span className="flex items-center gap-3">
          <span>{slotDuration}min slots</span>
          {adminTimeZone !== viewerTZ && (
            <span className="flex items-center gap-1">
              <Globe className="h-3 w-3" /> Host: {adminLabel}
            </span>
          )}
        </span>
      </div>
    </div>
  );
}

export default CalendarScheduler;

/**
 * MonthView - Monthly Calendar View
 *
 * Displays a traditional month grid (7 columns x 5-6 rows) showing all days
 * in the current month. When a date is selected, a side panel shows available
 * time slots for that day.
 *
 * Features:
 * - Standard month calendar grid
 * - Side panel with time slot buttons for selected date
 * - Highlights today and selected date
 * - Dims out-of-month and past dates
 */

import {
  eachDayOfInterval,
  endOfMonth,
  endOfWeek,
  format,
  isSameDay,
  isSameMonth,
  isToday,
  startOfMonth,
  startOfWeek,
} from "date-fns";
import { cn } from "@/lib/utils";
import { getAvailForDate, getSlotsForDate, isPastDate } from "./helpers";
import { SlotBtn } from "./slot-btn";
import type { Availability, BookedSlot } from "./types";

/**
 * Renders the month view with a side panel for time slots.
 */
export function MonthView({
  current,
  selectedDate,
  availability,
  bookedSlots,
  slotDuration,
  adminTZ,
  viewerTZ,
  onDateSelect,
  onSlotSelect,
}: {
  current: Date;
  selectedDate?: Date;
  availability: Availability[];
  bookedSlots: BookedSlot[];
  slotDuration: number;
  adminTZ: string;
  viewerTZ: string;
  onDateSelect: (d: Date) => void;
  onSlotSelect: (d: Date, t: string) => void;
}) {
  const days = eachDayOfInterval({
    start: startOfWeek(startOfMonth(current), { weekStartsOn: 0 }),
    end: endOfWeek(endOfMonth(current), { weekStartsOn: 0 }),
  });

  const selectedSlots =
    selectedDate &&
    getSlotsForDate(
      selectedDate,
      availability,
      bookedSlots,
      slotDuration,
      adminTZ,
      viewerTZ,
    );

  const shouldShowPanel =
    selectedDate &&
    isSameMonth(selectedDate, current) &&
    !isPastDate(selectedDate) &&
    selectedSlots &&
    selectedSlots.length > 0;
  return (
    <div className="w-full flex flex-col sm:flex-row gap-4">
      <div className="flex-1 pt-3 px-3 sm:px-0">
        <div className="grid grid-cols-7 mb-2 px-1">
          {["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].map((d) => (
            <div
              key={d}
              className="text-center text-[11px] font-medium text-muted-foreground"
            >
              {d}
            </div>
          ))}
        </div>

        <div className="grid grid-cols-7 gap-1 sm:pb-2 sm:pl-3 sm:gap-2">
          {days.map((day, i) => {
            const avail = getAvailForDate(day, availability, adminTZ);
            const slots = getSlotsForDate(
              day,
              availability,
              bookedSlots,
              slotDuration,
              adminTZ,
              viewerTZ,
            );

            const hasOpen = slots.some((s) => !s.booked);
            const isSelected = selectedDate && isSameDay(day, selectedDate);
            const inMonth = isSameMonth(day, current);
            const isPast = isPastDate(day);

            return (
              <button
                key={i}
                disabled={isPast}
                onClick={() => !isPast && onDateSelect(day)}
                className={cn(
                  "aspect-square rounded-xl flex items-center justify-center p-2 cursor-pointer sm:p-3 transition-all",
                  "border border-transparent",
                  "hover:bg-muted/60",
                  isSelected &&
                    "bg-primary hover:bg-primary/80 hover:text-primary-foreground text-primary-foreground",
                  !inMonth && "opacity-30",
                  isPast && "opacity-20 cursor-not-allowed",
                )}
              >
                <span
                  className={cn(
                    "text-sm font-medium",
                    isToday(day) && !isSelected && "text-primary",
                  )}
                >
                  {format(day, "d")}
                </span>
              </button>
            );
          })}
        </div>
      </div>

      {shouldShowPanel && (
        <div className="max-h-103.5 overflow-y-scroll no-scrollbar w-full sm:w-[320px] border-t sm:border-l sm:border-t-0 shrink-0 py-4 px-3 bg-background">
          <div className="mb-4">
            <p className="text-sm font-semibold">
              {format(selectedDate, "EEEE")}
            </p>
            <p className="text-xs text-muted-foreground">
              {format(selectedDate, "MMMM d")}
            </p>
          </div>

          <div className="grid grid-cols-2 gap-2">
            {selectedSlots.map((slot) => (
              <SlotBtn
                key={slot.adminTime}
                slot={slot}
                date={selectedDate}
                adminTZ={adminTZ}
                viewerTZ={viewerTZ}
                onSlotSelect={onSlotSelect}
              />
            ))}
          </div>
        </div>
      )}
      {!shouldShowPanel && (
        <div className="max-h-103.5 overflow-y-scroll no-scrollbar w-full sm:w-[320px] border-t sm:border-l sm:border-t-0 shrink-0 py-4 px-3 bg-background">
          <div className="mb-4">
            <p className="text-sm font-semibold">
              {format(selectedDate ?? new Date(), "EEEE")}
            </p>
            <p className="text-xs text-muted-foreground">
              {format(selectedDate ?? new Date(), "MMMM d")}
            </p>
          </div>
          <div className="text-sm h-30 flex items-center justify-center border rounded-xl border-dashed font-medium text-muted-foreground">
            No slots available
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * WeekView - Weekly Calendar View
 *
 * Displays a 7-day grid view with time slots on the Y-axis and days on the X-axis.
 * Shows all unique time slots across the week, allowing users to see availability
 * patterns at a glance.
 *
 * Features:
 * - Grid layout: time labels on left, 7 day columns
 * - Shows both viewer and host timezone times
 * - Color-coded slots: green=available, red=booked, gray=past
 * - Clickable day headers to select a specific date
 */

import {
  addDays,
  format,
  isBefore,
  isSameDay,
  isToday,
  startOfWeek,
} from "date-fns";
import { useMemo } from "react";
import { cn } from "@/lib/utils";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import {
  formatInAdmin,
  formatInViewer,
  generateTimeSlots,
  getAvailForDate,
  isBooked,
  isPastDate,
  slotToUtc,
} from "./helpers";
import type { Availability, BookedSlot } from "./types";

/**
 * Renders the week view showing 7 days in a grid.
 * Each row represents a unique time slot across the week.
 */
export function WeekView({
  current,
  selectedDate,
  availability,
  bookedSlots,
  slotDuration,
  adminTZ,
  viewerTZ,
  onDateSelect,
  onSlotSelect,
}: {
  current: Date;
  selectedDate?: Date;
  availability: Availability[];
  bookedSlots: BookedSlot[];
  slotDuration: number;
  adminTZ: string;
  viewerTZ: string;
  onDateSelect: (d: Date) => void;
  onSlotSelect: (d: Date, t: string) => void;
}) {
  const weekStart = startOfWeek(current, { weekStartsOn: 0 });
  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(weekStart, i));

  const allAdminTimes = useMemo(() => {
    const set = new Set<string>();
    weekDays.forEach((day) => {
      const avail = getAvailForDate(day, availability, adminTZ);
      if (avail)
        generateTimeSlots(avail.startTime, avail.endTime, slotDuration).forEach(
          (t) => set.add(t),
        );
    });
    return Array.from(set).sort();
  }, [weekDays, availability, slotDuration, adminTZ]);

  return (
    <div className="overflow-x-auto no-scrollbar">
      <div className="min-w-[600px]">
        <div
          className="grid border-b"
          style={{ gridTemplateColumns: "80px repeat(7, 1fr)" }}
        >
          <div className="py-2 px-2 text-xs justify-center flex flex-col text-muted-foreground items-center gap-0.5 font-medium">
            {adminTZ !== viewerTZ ? (
              <>
                <span className="block">Your TZ</span>
                <span className="block opacity-60">Host TZ</span>
              </>
            ) : (
              ""
            )}
          </div>
          {weekDays.map((day) => {
            const isSelected = selectedDate && isSameDay(day, selectedDate);
            const isPast = isPastDate(day);
            return (
              <button
                key={day.toISOString()}
                disabled={isPast}
                onClick={() => !isPast && onDateSelect(day)}
                className={cn(
                  "py-3 flex flex-col items-center gap-0.5 transition-colors",
                  isPast ? "opacity-40 cursor-not-allowed" : "hover:bg-accent",
                  !isPast && isSelected && "bg-primary/5",
                )}
              >
                <span className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
                  {format(day, "EEE")}
                </span>
                <span
                  className={cn(
                    "flex h-7 w-7 items-center justify-center rounded-full text-sm font-semibold",
                    isToday(day) && "bg-primary text-primary-foreground",
                    !isPast &&
                      isSelected &&
                      !isToday(day) &&
                      "ring-2 ring-primary text-primary",
                  )}
                >
                  {format(day, "d")}
                </span>
              </button>
            );
          })}
        </div>
        <ScrollArea className="h-[420px]">
          {allAdminTimes.length === 0 ? (
            <div className="flex items-center justify-center h-32 text-sm text-muted-foreground">
              No availability this week
            </div>
          ) : (
            allAdminTimes.map((adminTime) => {
              const repUtc = slotToUtc(weekDays[1], adminTime, adminTZ);
              return (
                <div
                  key={adminTime}
                  className="grid border-b last:border-b-0 hover:bg-muted/20 transition-colors"
                  style={{ gridTemplateColumns: "80px repeat(7, 1fr)" }}
                >
                  <div className="py-2 px-2 text-right pr-3 leading-none pt-2">
                    <span className="text-[10px] text-foreground font-mono block">
                      {formatInViewer(repUtc, viewerTZ)}
                    </span>
                    {adminTZ !== viewerTZ && (
                      <span className="text-[9px] text-muted-foreground font-mono block mt-0.5">
                        {formatInAdmin(repUtc, adminTZ)}
                      </span>
                    )}
                  </div>
                  {weekDays.map((day) => {
                    const avail = getAvailForDate(day, availability, adminTZ);
                    const exists = avail
                      ? generateTimeSlots(
                          avail.startTime,
                          avail.endTime,
                          slotDuration,
                        ).includes(adminTime)
                      : false;
                    const booked = isBooked(day, adminTime, bookedSlots);
                    const slotUtc = slotToUtc(day, adminTime, adminTZ);
                    const isPast = isBefore(slotUtc, new Date());
                    if (!exists)
                      return (
                        <div
                          key={day.toISOString()}
                          className="border-l py-1.5 px-1"
                        />
                      );
                    return (
                      <div
                        key={day.toISOString()}
                        className="border-l py-1 px-1"
                      >
                        <button
                          disabled={booked || isPast}
                          onClick={() => {
                            onDateSelect(day);
                            onSlotSelect(day, adminTime);
                          }}
                          className={cn(
                            "w-full rounded px-1 py-1.5 text-[10px] font-medium transition-all duration-150",
                            isPast
                              ? "bg-muted/50 text-muted-foreground cursor-not-allowed opacity-40"
                              : booked
                                ? "bg-rose-100 text-rose-400 dark:bg-rose-950/40 cursor-not-allowed line-through"
                                : "bg-emerald-50 text-emerald-700 hover:bg-primary hover:text-primary-foreground dark:bg-emerald-950/30 dark:text-emerald-400 active:scale-95",
                          )}
                        >
                          {isPast ? "Past" : booked ? "Booked" : "Open"}
                        </button>
                      </div>
                    );
                  })}
                </div>
              );
            })
          )}
        </ScrollArea>
      </div>
    </div>
  );
}

/**
 * DayView - Single Day Calendar View
 *
 * Displays all available time slots for a single selected date in a scrollable list.
 * Shows both viewer time and host time (when timezones differ).
 * Handles past dates, unavailable days, and booked slots gracefully.
 *
 * Features:
 * - Shows available slots as clickable buttons
 * - Disables past time slots and booked slots
 * - Displays booked count
 * - Tooltip on hover showing both timezones
 */

import { format, isBefore } from "date-fns";
import { Calendar1, Clock, Calendar } from "lucide-react";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { getAvailForDate, getSlotsForDate, isPastDate } from "./helpers";
import { SlotTip } from "./tooltip";
import type { Availability, BookedSlot } from "./types";

/**
 * Renders the day view for a specific date.
 * Shows a list of time slots that users can click to book.
 */
export function DayView({
  current,
  availability,
  bookedSlots,
  slotDuration,
  adminTZ,
  viewerTZ,
  onSlotSelect,
}: {
  current: Date;
  availability: Availability[];
  bookedSlots: BookedSlot[];
  slotDuration: number;
  adminTZ: string;
  viewerTZ: string;
  onDateSelect: (d: Date) => void;
  onSlotSelect: (d: Date, t: string) => void;
}) {
  const avail = getAvailForDate(current, availability, adminTZ);
  const slots = getSlotsForDate(
    current,
    availability,
    bookedSlots,
    slotDuration,
    adminTZ,
    viewerTZ,
  );
  const bookedCount = slots.filter((s) => s.booked).length;
  const isPast = isPastDate(current);

  return (
    <div className="p-6">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h3 className="md:text-lg text-base font-medium">
            {format(current, "EEEE")}
          </h3>
          <p className="text-xs md:text-sm text-muted-foreground">
            {format(current, "MMMM d, yyyy")}
          </p>
        </div>
        {isPast ? (
          <Badge variant="outline" className="text-muted-foreground">
            Past date
          </Badge>
        ) : avail ? (
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            {/*<Clock className="h-3.5 w-3.5" />*/}
            {/*<span>*/}
            {/*{formatInViewer(
                slotToUtc(current, avail.startTime, adminTZ),
                viewerTZ,
              )}
              {" – "}
              {formatInViewer(
                slotToUtc(current, avail.endTime, adminTZ),
                viewerTZ,
              )}*/}
            {/*{adminTZ !== viewerTZ && (
                <span className="ml-1 text-[10px]">(your time)</span>
              )}*/}
            {/*</span>*/}
            {bookedCount > 0 && (
              <Badge variant="secondary" className="text-xs">
                {bookedCount} booked
              </Badge>
            )}
          </div>
        ) : (
          <Badge variant="outline" className="text-muted-foreground">
            Unavailable
          </Badge>
        )}
      </div>

      {isPast ? (
        <div className="flex flex-col items-center justify-center h-40 gap-2 text-muted-foreground border-2 border-dashed rounded-xl">
          <Calendar className="h-8 w-8 opacity-30" />
          <p className="text-sm">This date is in the past</p>
        </div>
      ) : slots.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-40 gap-2 text-muted-foreground border-2 border-dashed rounded-xl">
          <Calendar1 className="h-8 w-8 opacity-30" />
          <p className="text-sm">No available slots for this day</p>
        </div>
      ) : (
        <ScrollArea className="h-[360px] pr-2">
          <div className="space-y-2">
            {slots.map((slot) => {
              const isPast = isBefore(new Date(slot.utc), new Date());

              return (
                <TooltipProvider key={slot.adminTime} delayDuration={80}>
                  <Tooltip>
                    <TooltipTrigger asChild>
                      <button
                        disabled={slot.booked || isPast}
                        onClick={() => onSlotSelect(current, slot.adminTime)}
                        className={cn(
                          "w-full flex items-center justify-between px-4 py-3 rounded-xl border text-sm font-medium transition-all duration-150",
                          slot.booked
                            ? "bg-muted/50 border-border text-muted-foreground cursor-not-allowed"
                            : "bg-background border-border hover:border-primary hover:bg-primary/5 hover:text-primary active:scale-[0.99]",
                        )}
                      >
